(26,'wallybot','1','private','outgoing',NULL,'Запомнил!\nТеперь на запросы о *\"новости\"* я буду отвечать:\n\n_лента новостей_',NULL,NULL,NULL,'{\"inline_keyboard\":[[{\"text\":\"Научить ещё\",\"callback_data\":\"cmd_learn\"},{\"text\":\"Посмотреть всё\",\"callback_data\":\"cmd_knowledge\"}]]}',NULL,NULL,0,NULL,NULL,1,'2026-03-07 05:55:31','2026-03-07 05:55:31'),
