INSERT INTO `Wo_Bot_Tasks` VALUES
(1,'wallybot',1,'1','как найти бота в мессенджере','Открой вкладку Чаты и нажми на иконку робота (Bot Store), либо используй поиск по имени/@username бота.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(2,'wallybot',1,'1','як знайти бота в месенджері','Відкрий вкладку Чати та натисни на іконку робота (Bot Store), або скористайся пошуком за ім’ям/@username бота.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(3,'wallybot',1,'1','як знайти бота в месенджері','Відкрий вкладку Чати та натисни на іконку робота (Bot Store), або скористайся пошуком за ім’ям/@username бота.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(4,'wallybot',1,'1','как запустить бота','Открой чат бота и нажми START, после этого отправь /help для списка команд.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(5,'wallybot',1,'1','как создать своего бота','Открой Bot Store → Мои боты → Создать бота. Заполни username, display name, описание и сохрани bot_token.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(6,'wallybot',1,'1','как создать своего бота','Открой Bot Store → Мои боты → Создать бота. Заполни username, display name, описание и сохрани bot_token.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(7,'wallybot',1,'1','як створити свого бота','Відкрий Bot Store → Мої боти → Створити бота. Заповни username, display name, опис і збережи bot_token.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(8,'wallybot',1,'1','что умеют боты','Боты могут отвечать на FAQ, отправлять уведомления/новости, создавать опросы, помогать с задачами и поддержкой.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(9,'wallybot',1,'1','что умеют боты','Боты могут отвечать на FAQ, отправлять уведомления/новости, создавать опросы, помогать с задачами и поддержкой.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(10,'wallybot',1,'1','как добавить бота в группу','Если бот поддерживает группы, открой профиль бота и добавь его в нужную группу через меню участников.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(11,'wallybot',1,'1','как заблокировать бота','Открой чат с ботом → профиль бота → Block Bot. Разблокировка: Settings → Privacy → Blocked list.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(12,'wallybot',1,'1','как заблокировать бота','Открой чат с ботом → профиль бота → Block Bot. Разблокировка: Settings → Privacy → Blocked list.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(13,'wallybot',1,'1','как использовать команды бота','Команды начинаются с /. Нажми кнопку / возле поля ввода или отправь вручную: /start, /help, /settings и т.д.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(14,'wallybot',1,'1','як користуватись командами бота','Команди починаються з /. Натисни кнопку / біля поля вводу або надішли вручну: /start, /help, /settings.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(15,'wallybot',1,'1','як користуватись командами бота','Команди починаються з /. Натисни кнопку / біля поля вводу або надішли вручну: /start, /help, /settings.','done','low',NULL,NULL,NULL,NULL,'2026-03-05 10:03:30','2026-03-05 10:03:30'),
(16,'wallybot',1,'1','новости','лента новостей','done','low',NULL,NULL,NULL,NULL,'2026-03-07 05:55:31','2026-03-07 05:55:31');
