INSERT INTO `Wo_CustomPages` VALUES
(1,'callback','callback','Платеж осуществлен успешно',1),
(2,'safety_and_security','Принципы безопасности и защиты пользователей','WorldMates строго соблюдает политику Google Play и международные нормы в отношении безопасности и защиты пользователей. Мы категорически осуждаем и запрещаем любые формы эксплуатации, насилия или неприемлемого контента, включая сексуальное насилие над детьми. <br> <br>? Запрещённый контент <br>Наше приложение не допускает распространения, хранения или обмена любыми материалами, связанными с эксплуатацией несовершеннолетних. Любые подобные нарушения приведут к немедленной блокировке аккаунта и передаче информации в компетентные органы. <br> <br>? Модерация и защита пользователей <br>Мы используем автоматизированные системы и команды модераторов для мониторинга контента и обеспечения безопасного взаимодействия пользователей. Если вы заметили нарушение, вы можете сообщить нам через встроенные инструменты жалоб. <br> <br>? Соответствие законам <br>WorldMates придерживается всех действующих законов о защите детей и сотрудничает с соответствующими организациями для предотвращения незаконных действий. <br> <br>Наша цель — создать безопасную и комфортную среду для общения, где каждый пользователь может чувствовать себя защищённым.',1),
(3,'Legal_Information','Юридическая информация','Worldmates.club — международное онлайн-сообщество. <br>Юридическое имя: Worldmates social. <br>Юридический адрес: Украина, 49000, г. Днепр. <br>Электронная почта: support@worldmates.club. <br>Дата основания: 19.05.2024. <br>Юрисдикция: Деятельность регулируется законодательством Украины.',1);
