(2,'invite','<p>Hi there, <br><br>You have received an invitation request from your friend <a style=\"color: {{backgound_color}};\" href=\"{{URL}}\">{{NAME}}</a> to join our social network community <a style=\"color: {{backgound_color}};\" href=\"{{SITE_URL}}/register?ref={{USERNAME}}\">{{SITE_NAME}}</a>.<br><br><a style=\"color: &lt;?php echo $wo[\'config\'][\'btn_background_color\'];\" href=\"{{SITE_URL}}/register?ref={{USERNAME}}\">Let\'s contact &amp; find your friends !</a> <br><br>{{SITE_NAME}} Team. <br>Best regards.</p>'),
(3,'login_with','<p>Hello {{FIRST_NAME}}, <br><br>Thank you for joining {{SITE_NAME}}!<br><br>Your temporary login credentials are: <br><br>Username: {{USERNAME}}<br>Password: {{EMAIL}}<br><br>Please change your password as soon as possible to fully secure your account. <br><br>Best Regards,<br>{{SITE_NAME}} Team.</p>'),
(4,'notification','<p>&nbsp;</p>\n<table class=\"body-wrap\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; width: 100%; background-color: #f6f6f6; margin: 0;\" bgcolor=\"#f6f6f6\">\n<tbody>\n<tr style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; margin: 0;\">\n<td style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; vertical-align: top; margin: 0;\" valign=\"top\">&nbsp;</td>\n<td class=\"container\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; vertical-align: top; display: block !important; max-width: 600px !important; clear: both !important; margin: 0 auto;\" valign=\"top\" width=\"600\">\n<div class=\"content\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; max-width: 600px; display: block; margin: 0 auto; padding: 20px;\">\n<table class=\"main\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; border-radius: 3px; background-color: #fff; margin: 0; border: 1px solid #e9e9e9;\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" bgcolor=\"#fff\">\n<tbody>\n<tr style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; margin: 0;\">\n<td class=\"alert alert-warning\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 16px; vertical-align: top; color: #fff; font-weight: 500; text-align: center; border-radius: 3px 3px 0 0; background-color: #e24141; margin: 0; padding: 10px;\" align=\"center\" valign=\"top\" bgcolor=\"#FF9F00\">New notification from {{SITE_NAME}}</td>\n</tr>\n<tr style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; margin: 0;\">\n<td class=\"content-wrap\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; vertical-align: top; margin: 0; padding: 20px;\" valign=\"top\">\n<table style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; margin: 0;\" width=\"100%\" cellspacing=\"0\" cellpadding=\"0\">\n<tbody>\n<tr style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; margin: 0;\">\n<td class=\"content-block\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; vertical-align: top; margin: 0; padding: 0 0 20px;\" valign=\"top\"><a style=\"text-decoration: none; color: #444;\" href=\"{{NOTIFY_URL}}\"><img style=\"width: 60px; float: left; border-radius: 100px; margin-right: 10px;\" src=\"{{NOTIFY_AVATAR}}\" alt=\"\"> {{NOTIFY_NAME}}</a>\n<div style=\"color: #666; font-size: 12px;\"><strong> {{TEXT_TYPE}}: </strong> {{TEXT}}</div>\n</td>\n</tr>\n<tr style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; margin: 0;\">\n<td class=\"content-block\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 14px; vertical-align: top; margin: 0; padding: 0 0 5px;\" valign=\"top\"><a class=\"btn-primary\" style=\"font-family: \'Helvetica Neue\',Helvetica,Arial,sans-serif; box-sizing: border-box; font-size: 12px; color: #fff; text-decoration: none; line-height: 2em; font-weight: bold; text-align: center; cursor: pointer; display: inline-block; border-radius: 5px; text-transform: capitalize; background-color: #a84849; margin: 0; border-color: #a84849; border-style: solid; border-width: 4px 10px;\" href=\"{{URL}}\">View on {{SITE_NAME}}</a></td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n</div>\n</td>\n</tr>\n</tbody>\n</table>'),
(5,'payment_declined','<p>Hello {{name}}, <br><br>Unfortunately your payment of ${{amount}} was declined. <br><br>For more info, please reply to this email. <br><br>Kind regards,<br>{{site_name}} Team</p>'),
(6,'payment_approved','<p>Hello {{name}}, <br><br>Your payment request of ${{amount}} is approved. <br><br>We have sent you money ! <br><br>Kind regards,<br>{{site_name}} Team</p>'),
(7,'recover','<p>Hello {{USERNAME}}, <br><br>To reset your password <a href=\"{{LINK}}\">Click Here</a> <br><br>{{SITE_NAME}} Team, <br>Regards,</p>'),
(8,'unusual_login','<p>Hi {{USERNAME}},<br><br>Please verify that it&rsquo;s you<br><br>Your sign in attempt seems a little different than usual. This could be because you are signing in from a different device or a different location.<br><br>If you are attempting to sign-in, please use the following code to confirm your identity:<br><br>{{CODE}}<br><br>Here are the details of the sign-in attempt:<br>Date: {{DATE}}<br>Account: {{EMAIL}}<br>Location: {{COUNTRY_CODE}}<br>IP Address: {{IP_ADDRESS}}<br>City: {{CITY}}<br><br>If this wasn&rsquo;t you, please reset your password.<br><br>Yours securely,<br>Team {{SITE_NAME}}</p>'),
(9,'account_deleted','<p>Hi {{name}},<br><br>We are here to inform you that your account on {{SITE_NAME}} was deleted and all your data were erased.<br><br>Best regards,<br>{{SITE_NAME}} team.</p>');
